import createDebug from"debug";import{Readable}from"stream";import{createHash}from"crypto";import{dataUriToBuffer}from"data-uri-to-buffer";import NotModifiedError from"./notmodified.js";const debug=createDebug("get-uri:data");class DataReadable extends Readable{constructor(e,a){super(),this.push(a),this.push(null),this.hash=e}}export const data=async({href:e},{cache:a}={})=>{const r=createHash("sha1");r.update(e);const t=r.digest("hex");if(debug('generated SHA1 hash for "data:" URI: %o',t),a?.hash===t)throw debug("got matching cache SHA1 hash: %o",t),new NotModifiedError;{debug('creating Readable stream from "data:" URI buffer');const{buffer:a}=dataUriToBuffer(e);return new DataReadable(t,Buffer.from(a))}};